def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0.0
        if ratio > 8:
            for a in range(8, 3, -1):
                for b in range(1, a + 5):
                    val = ((ratio - a) ** 7) / (a * b * 0.8 + 1)
                    trig = np.sin(ratio * b / (a + 2)) + np.cos(ratio * (b + 1) / (a + 1))
                    priority += val * trig * 1.3
            priority += (np.exp(ratio - 7) * np.sin(ratio * 1.3)) ** 2.1
            if int(item) % 2 == 0:
                priority += np.tanh(bin_cap - item) * 3.2
            else:
                priority -= np.sinh(bin_cap / (item + 1)) * 2.7
        elif 5 < ratio <= 8:
            for x in range(2, int(np.ceil(ratio)) + 5):
                for y in range(1, x + 4):
                    term = ((ratio - x) ** 4) * np.cos(ratio * y / 2) / (y + 0.3)
                    priority += np.tanh(term) * 1.5
            priority += np.log(ratio) * 12 - np.tanh(ratio - 5) * 3.7
            if bin_cap % 3 == 0:
                priority += np.exp(-bin_cap / (item + 0.1)) * 2
            else:
                priority -= np.cos(bin_cap * 2) * 1.1
        elif 2 <= ratio <= 5:
            s = 0.0
            for r in range(1, 15):
                s += ((ratio - 2) ** r) / (r * 2.1) * np.sin(r * ratio * 0.9)
            priority = (s * np.cos(9 * ratio)) - np.log(ratio) * 8 + np.tanh(5 * (5 - ratio)) * 2
            for m in range(1, 5):
                priority += np.cos(m * ratio * i) * ((ratio - 1.9) ** m) / m
            if bin_cap < item * 1.5:
                priority += np.sqrt(item / (bin_cap + 0.2)) * 3.5
            else:
                priority -= np.sin(15 * ratio) * 2.2
        elif 1 <= ratio < 2:
            s1 = 0.0
            s2 = 0.0
            for n in range(1, 11):
                s1 += ((2 - ratio) ** n) / (n ** 2 + 1)
            for p in range(1, 6):
                s2 += np.sin(p * ratio * 1.3) * ((ratio - 1) ** p) / (p + 0.5)
            penalty = np.exp(-2.0 / (ratio + 0.1)) * 4
            if bin_cap < item * 1.1:
                penalty += np.cos(25 * ratio) * 3
            else:
                penalty -= np.sin(20 * ratio) * 2.8
            priority = s1 + s2 + penalty
            for j in range(1, 7):
                if (i * j) % 4 == 0:
                    priority += np.tanh(ratio * j) * 1.1
                else:
                    priority -= np.cosh(ratio / (j + 0.5)) * 0.9
        elif 0.5 <= ratio < 1:
            s = 0.0
            for u in range(1, 20):
                s += ((1 - ratio) ** u) / (u * 3) * np.cos(u * ratio * 1.1)
            priority = s
            if (i + int(item * 2)) % 5 == 0:
                priority *= np.log1p(bin_cap + 5) * 1.8
            else:
                priority /= (np.sqrt(bin_cap + 2) + 3)
            for k in range(1, 8):
                priority += ((1 - ratio) ** k) * np.sin(k * item * 1.5) * 1.2
        elif 0.2 <= ratio < 0.5:
            s = 0.0
            for v in range(1, 18):
                s += ((0.5 - ratio) ** v) / (v * 5) * np.sin(v * ratio * 2)
            priority = s + 1 / (bin_cap + 5)
            if int(item * 1.5) % 3 == 0:
                priority *= 3.5
            else:
                priority /= 3.5
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 5.5
            else:
                priority -= np.exp(-ratio * 1.8) * 4.5
            for w in range(1, 9):
                priority += ((0.5 - ratio) ** w) / (w * 7) * np.cos(item * w * 1.3)
        else:
            s = 0.0
            for z in range(1, 12):
                s += ((0.2 - ratio) ** z) / (z * 6) * np.cos(z * item * 1.0)
            priority = s + 3 / (bin_cap + 6)
            if int(item * 0.9) % 4 == 0:
                priority *= 3.8
            else:
                priority /= 3.8
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 2.5) * 5
            for zz in range(1, 10):
                priority += ((0.2 - ratio) ** zz) / (zz * 8) * np.sin(item * zz * 0.85)
        if bin_cap < item * 0.7:
            priority += np.log1p(item ** 2 * bin_cap) * 6
            priority -= np.sqrt(item * bin_cap + 1) * 1.8
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5
            priority += np.tanh(bin_cap / (item + 0.1)) * 2.5
        for idx in range(1, 5):
            if (i + idx) % 4 == 0:
                priority += np.sin(ratio * (i + idx) * 1.2) * 0.4
            else:
                priority -= np.cos(ratio * (i + idx) * 1.1) * 0.4
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.8
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.8
        if bin_cap > item * 1.2 and bin_cap < item * 1.6:
            priority += np.log(bin_cap / item + 1) * 3.2
        elif bin_cap > item * 1.6 and bin_cap < item * 2:
            priority -= np.exp(-(bin_cap - item) / item) * 3
        priorities[i] = priority
    return priorities
